"use client";

import { useEffect, useState } from 'react';

export interface ExportHistoryItem {
  id: string;
  topic: string;
  platform: string;
  timestamp: string;
}

export interface Telemetry {
  generated: number;
  exported: number;
  lastActivity: string | null;
  history: ExportHistoryItem[];
}

const STORAGE_KEY = 'artenova_telemetry';

const defaultStats: Telemetry = {
  generated: 0,
  exported: 0,
  lastActivity: null,
  history: [],
};

export function useTelemetry() {
  const [stats, setStats] = useState<Telemetry>(defaultStats);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        // Migrating old data if history doesn't exist
        setStats({
          ...defaultStats,
          ...parsed,
          history: parsed.history || []
        });
      } catch (e) {
        console.error("Failed to load telemetry", e);
      }
    }
  }, []);

  const trackGeneration = () => {
    const newStats = {
      ...stats,
      generated: stats.generated + 1,
      lastActivity: new Date().toISOString(),
    };
    save(newStats);
  };

  const trackExport = (topic: string, platform: string) => {
    const newItem: ExportHistoryItem = {
      id: Math.random().toString(36).substr(2, 9),
      topic,
      platform,
      timestamp: new Date().toISOString(),
    };

    const newHistory = [newItem, ...stats.history].slice(0, 10);

    const newStats = {
      ...stats,
      exported: stats.exported + 1,
      lastActivity: new Date().toISOString(),
      history: newHistory,
    };
    save(newStats);
  };

  const save = (newStats: Telemetry) => {
    setStats(newStats);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(newStats));
  };

  return { 
    ...stats, 
    exportRate: stats.generated > 0 ? Math.round((stats.exported / stats.generated) * 100) : 0,
    trackGeneration, 
    trackExport 
  };
}
